Here's a minimal API endpoint that accepts multiple images plus a description via `multipart/form-data`:

```csharp
// Program.cs

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size (default is ~30 MB)
builder.WebHost.ConfigureKestrel(o => o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (
    IFormFileCollection files,       // bound from all file parts
    [FromForm] string description,   // bound from the "description" field
    CancellationToken ct) =>
{
    if (files.Count == 0)
        return Results.BadRequest("No files uploaded.");

    var allowed = new[] { "image/jpeg", "image/png", "image/gif", "image/webp" };
    var saved = new List<string>();

    foreach (var file in files)
    {
        if (!allowed.Contains(file.ContentType, StringComparer.OrdinalIgnoreCase))
            return Results.BadRequest($"'{file.FileName}' is not an allowed image type.");

        // Save to a target directory (swap with blob storage, etc.)
        var dest = Path.Combine("uploads", $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}");
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(dest);
        await file.CopyToAsync(stream, ct);
        saved.Add(dest);
    }

    return Results.Ok(new { description, fileCount = saved.Count, paths = saved });
})
.DisableAntiforgery()                       // required for form binding without anti-forgery tokens
.Accepts<IFormFileCollection>("multipart/form-data");

app.Run();
```

**Key points:**

| Concern | How it's handled |
|---|---|
| **50 MB limit** | `MaxRequestBodySize` on Kestrel |
| **Multiple files** | `IFormFileCollection` binds every file part |
| **Text field** | `[FromForm] string description` binds the named form field |
| **Validation** | Content-type allowlist before saving |
| **Anti-forgery** | `.DisableAntiforgery()` — needed when there's no token (API clients, SPAs) |

**Example `curl` to test it:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=My vacation photos" \
  -F "files=@photo1.jpg" \
  -F "files=@photo2.png"
```

> If you're behind a reverse proxy (IIS, Nginx), you'll also need to raise *its* request size limit (e.g., `client_max_body_size 50m;` for Nginx, or `maxAllowedContentLength` for IIS).
